/**
 * Calcula el factorial de un número entero no negativo.
 * 
 * @param {number} n - El número entero no negativo.
 * @returns {number} El factorial del número.
 * @throws {Error} Si el número es negativo o no es un entero.
 */
function factorial(n) {
    if (!Number.isInteger(n)) {
        throw new Error('El número debe ser un entero.');
    }
    if (n < 0) {
        throw new Error('El número no puede ser negativo.');
    }
    if (n === 0 || n === 1) {
        return 1;
    }
    return n * factorial(n - 1);
}

// Pruebas unitarias
describe('Función factorial', () => {
    it('Debería calcular el factorial de 5', () => {
        expect(factorial(5)).toBe(120);
    });
    it('Debería calcular el factorial de 0', () => {
        expect(factorial(0)).toBe(1);
    });
    it('Debería calcular el factorial de 1', () => {
        expect(factorial(1)).toBe(1);
    });
    it('Debería lanzar un error para números negativos', () => {
        expect(() => factorial(-1)).toThrowError('El número no puede ser negativo.');
    });
    it('Debería lanzar un error para números no enteros', () => {
        expect(() => factorial(1.5)).toThrowError('El número debe ser un entero.');
    });
});

// Pruebas de integración
describe('Integración con otros componentes', () => {
    it('Debería funcionar con números grandes', () => {
        expect(factorial(20)).toBe(2432902008176640000);
    });
    it('Debería funcionar con números pequeños', () => {
        expect(factorial(3)).toBe(6);
    });
});

