// Función para generar saludo
function generarSaludo(nombre) {
    if (!nombre) {
        throw new Error("El nombre no puede ser vacío o nulo");
    }
    const saludo = `Hola, ${nombre}!`;
    return saludo;
}

// Función de prueba
function probarGenerarSaludo() {
    try {
        console.log(generarSaludo("Juan")); // Debe imprimir "Hola, Juan!"
        console.log(generarSaludo("")); // Debe lanzar un error
    } catch (error) {
        console.error(error.message); // Debe imprimir "El nombre no puede ser vacío o nulo"
    }
}

// Pruebas unitarias
function probarUnitario() {
    try {
        generarSaludo(null); // Debe lanzar un error
    } catch (error) {
        console.error(error.message); // Debe imprimir "El nombre no puede ser vacío o nulo"
    }

    try {
        generarSaludo(undefined); // Debe lanzar un error
    } catch (error) {
        console.error(error.message); // Debe imprimir "El nombre no puede ser vacío o nulo"
    }

    try {
        generarSaludo("Maria"); // Debe imprimir "Hola, Maria!"
        console.log(generarSaludo("Maria")); // Debe imprimir "Hola, Maria!"
    } catch (error) {
        console.error(error.message);
    }
}

// Integración y pruebas de integración
function integrarYProbar() {
    const nombres = ["Pedro", "Ana", "Luis"];
    nombres.forEach((nombre) => {
        try {
            console.log(generarSaludo(nombre)); // Debe imprimir saludos con cada nombre
        } catch (error) {
            console.error(error.message);
        }
    });
}

// Ejecutar pruebas
probarGenerarSaludo();
probarUnitario();
integrarYProbar();
